function Get-ButtonText {
    param($btnName)
    $search = [System.Text.Encoding]::UTF8.GetBytes("$btnName.textContent = '")
    $pos = 0
    for ($i = 0; $i -lt $bytes.Length - $search.Length; $i++) {
        $match = $true
        for ($j = 0; $j -lt $search.Length; $j++) {
            if ($bytes[$i+$j] -ne $search[$j]) { $match = $false; break }
        }
        if ($match) { $pos = $i + $search.Length; break }
    }
    if ($pos -gt 0) {
        # Read bytes until closing quote
        $result = @()
        for ($k = $pos; $k -lt $pos+20; $k++) {
            if ($bytes[$k] -eq 0x27) { break }  # closing '
            $result += $bytes[$k]
        }
        "$btnName bytes: " + ($result | ForEach-Object { "{0:X2}" -f $_ }) -join " "
    }
}

